  console.error("Missing SVIX_AUTH_TOKEN environment variable.");
  process.exit(1);
}

const appId = process.argv[2];
const msgId = process.argv[3];

if (!appId || !msgId) {
  console.error("Usage: node index.js <appId> <msgId>");
  process.exit(1);
}

